4571 static Value *simplifyCmpSelOfMaxMin(Value *CmpLHS, Value *CmpRHS,
4572                                      ICmpInst::Predicate Pred, Value *TVal,
4573                                      Value *FVal) {
4574   // Canonicalize common cmp+sel operand as CmpLHS.
4575   if (CmpRHS == TVal || CmpRHS == FVal) {
4576     std::swap(CmpLHS, CmpRHS);
4577     Pred = ICmpInst::getSwappedPredicate(Pred);
4578   }
4579 
4580   // Canonicalize common cmp+sel operand as TVal.
4581   if (CmpLHS == FVal) {
4582     std::swap(TVal, FVal);
4583     Pred = ICmpInst::getInversePredicate(Pred);
4584   }
4585 
4586   // A vector select may be shuffling together elements that are equivalent
4587   // based on the max/min/select relationship.
4588   Value *X = CmpLHS, *Y = CmpRHS;
4589   bool PeekedThroughSelectShuffle = false;
4590   auto *Shuf = dyn_cast<ShuffleVectorInst>(FVal);
4591   if (Shuf && Shuf->isSelect()) {
4592     if (Shuf->getOperand(0) == Y)
4593       FVal = Shuf->getOperand(1);
4594     else if (Shuf->getOperand(1) == Y)
4595       FVal = Shuf->getOperand(0);
4596     else
4597       return nullptr;
4598     PeekedThroughSelectShuffle = true;
4599   }
4600 
4601   // (X pred Y) ? X : max/min(X, Y)
4602   auto *MMI = dyn_cast<MinMaxIntrinsic>(FVal);
4603   if (!MMI || TVal != X ||
4604       !match(FVal, m_c_MaxOrMin(m_Specific(X), m_Specific(Y))))
4605     return nullptr;
4606 
4607   // (X >  Y) ? X : max(X, Y) --> max(X, Y)
4608   // (X >= Y) ? X : max(X, Y) --> max(X, Y)
4609   // (X <  Y) ? X : min(X, Y) --> min(X, Y)
4610   // (X <= Y) ? X : min(X, Y) --> min(X, Y)
4611   //
4612   // The equivalence allows a vector select (shuffle) of max/min and Y. Ex:
4613   // (X > Y) ? X : (Z ? max(X, Y) : Y)
4614   // If Z is true, this reduces as above, and if Z is false:
4615   // (X > Y) ? X : Y --> max(X, Y)
4616   ICmpInst::Predicate MMPred = MMI->getPredicate();
4617   if (MMPred == CmpInst::getStrictPredicate(Pred))
4618     return MMI;
4619 
4620   // Other transforms are not valid with a shuffle.
4621   if (PeekedThroughSelectShuffle)
4622     return nullptr;
